#include <stdio.h>
#include <limits.h>
int findMinCoins(int* coinDenominations, int coinDenominationsSize, int totalAmount) {
    int dp[totalAmount + 1];
    for (int i = 0; i <= totalAmount; i++) {
        dp[i] = INT_MAX;
    }
    dp[0] = 0;
    for (int i = 1; i <= totalAmount; i++) {
        for (int j = 0; j < coinDenominationsSize; j++) {
            if (i >= coinDenominations[j]) {
                dp[i] = (dp[i] < dp[i - coinDenominations[j]] + 1) ? dp[i] : dp[i - coinDenominations[j]] + 1;
            }
        }
    }
    return dp[totalAmount] == INT_MAX ? -1 : dp[totalAmount];
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int coinDenominationsSize;
        scanf("%d", &coinDenominationsSize);
        int* coinDenominations = (int*)malloc(coinDenominationsSize * sizeof(int));
        for (int i = 0; i < coinDenominationsSize; i++) {
            scanf("%d", &coinDenominations[i]);
        }
        int totalAmount;
        scanf("%d", &totalAmount);
        printf("%d\n", findMinCoins(coinDenominations, coinDenominationsSize, totalAmount));
        free(coinDenominations);
    }
    return 0;
}

