import java.util.Scanner;
public class Main {
    public static int findMinCoins(int[] coinDenominations, int totalAmount) {
        int[] dp = new int[totalAmount + 1];
        for (int i = 0; i <= totalAmount; i++) {
            dp[i] = Integer.MAX_VALUE;
        }
        dp[0] = 0;
        for (int i = 1; i <= totalAmount; i++) {
            for (int j = 0; j < coinDenominations.length; j++) {
                if (i >= coinDenominations[j]) {
                    dp[i] = Math.min(dp[i], dp[i - coinDenominations[j]] + 1);
                }
            }
        }
        return dp[totalAmount] == Integer.MAX_VALUE ? -1 : dp[totalAmount];
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int coinDenominationsSize = scanner.nextInt();
            int[] coinDenominations = new int[coinDenominationsSize];
            for (int i = 0; i < coinDenominationsSize; i++) {
                coinDenominations[i] = scanner.nextInt();
            }
            int totalAmount = scanner.nextInt();
            System.out.println(findMinCoins(coinDenominations, totalAmount));
        }
    }
}

