def find_min_coins(coin_denominations, total_amount):
    dp = [float('inf')] * (total_amount + 1)
    dp[0] = 0
    for i in range(1, total_amount + 1):
        for coin in coin_denominations:
            if i >= coin:
                dp[i] = min(dp[i], dp[i - coin] + 1)
    return dp[total_amount] if dp[total_amount] != float('inf') else -1

